30	  const newPost: Post = {
31	    id: nextId(posts),
32	    title,
33	    content,
34	    userId: userId || 1,
35	    createdAt: new Date().toISOString(),
36	  };
37	  posts.push(newPost);
38	  res.status(201).json(newPost);
