import { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";

export const JWT_SECRET = "super-secret-key";

// Augment Express Request to include the decoded user payload
declare global {
  namespace Express {
    interface Request {
      user?: {
        userId: number;
        username: string;
      };
    }
  }
}

export function authenticate(req: Request, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith("Bearer ")) {
    res.status(401).json({ error: "Unauthorized" });
    return;
  }

  const token = authHeader.slice(7); // Remove "Bearer " prefix

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as { userId: number; username: string };
    req.user = { userId: decoded.userId, username: decoded.username };
    next();
  } catch {
    res.status(401).json({ error: "Invalid token" });
  }
}
```

**TypeScript notes for this file:**
- `jwt.verify()` returns `string | JwtPayload`. We cast it with `as { userId: number; username: string }` after the try block assures it succeeded. The `catch` block uses no bound variable (the bare `catch {}` form) to satisfy strict mode since we don't need the error value.
- The `declare global { namespace Express { interface Request { ... } } }` pattern is required — not just `namespace Express { ... }` — because the file has imports and is therefore a module in TypeScript's type system. Without `declare global`, the augmentation would be scoped locally and not affect Express's global types.
- `(req, res, next): void` matches the signature pattern in `logger.ts`.

